diff --git a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
index e0f629e14f65..3551491ab6d4 100644
--- a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
+++ b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
@@ -2794,6 +2794,46 @@ void InnerLoopVectorizer::fixupIVUsers(PHINode *OrigPhi,
   Value *EndValue = cast<PHINode>(OrigPhi->getIncomingValueForBlock(
                                       OrigLoop->getLoopPreheader()))
                         ->getIncomingValueForBlock(MiddleBlock);
+  
+  // Adjust EndValue to represent the value from the last active lane in the
+  // vector loop rather than lane 0. The middle.block receives the vector exit
+  // value produced in the vector loop body; for uniform inductions with outside
+  // uses, the correct value after the vectorized iterations corresponds to the
+  // final lane\x27s increment. Compute EndValueLastLane = EndValue + (VF-1) * Step.
+  {
+    IRBuilder<> B(MiddleBlock->getTerminator());
+    if (isa_and_nonnull<FPMathOperator>(II.getInductionBinOp()))
+      B.setFastMathFlags(II.getInductionBinOp()->getFastMathFlags());
+    VPValue *StepVPV = Plan.getSCEVExpansion(II.getStep());
+    assert(StepVPV && "step must have been expanded during VPlan execution");
+    Value *Step = StepVPV->isLiveIn() ? StepVPV->getLiveInIRValue()
+                                      : State.get(StepVPV, VPLane(0));
+    unsigned VFMinus1 = State.VF.getKnownMinValue() - 1;
+    if (VFMinus1) {
+      Value *VFMinus1Val = B.getInt32(VFMinus1);
+      Value *ScaledStep = nullptr;
+      if (EndValue->getType()->isIntegerTy()) {
+        Value *VFext = B.CreateZExtOrTrunc(VFMinus1Val, Step->getType());
+        ScaledStep = B.CreateMul(VFext, Step);
+        EndValue = B.CreateAdd(EndValue, ScaledStep);
+      } else if (EndValue->getType()->isPointerTy()) {
+        // For pointer inductions, Step is integer-typed. Scale and add via ptr add.
+        Value *StepInt = Step->getType()->isIntegerTy() ? Step : B.getInt64(0);
+        Value *ScaleInt = B.CreateZExtOrTrunc(VFMinus1Val, B.getInt64Ty());
+        Value *ScaledStepInt = B.CreateMul(ScaleInt, B.CreateZExtOrTrunc(StepInt, B.getInt64Ty()));
+        EndValue = B.CreatePtrAdd(EndValue, ScaledStepInt);
+      } else {
+        // Floating point induction: add (VF-1)*Step
+        Value *VFfp = B.CreateSIToFP(VFMinus1Val, Step->getType());
+        ScaledStep = B.CreateFMul(VFfp, Step);
+        EndValue = B.CreateBinOp(II.getInductionBinOp()->getOpcode() == Instruction::FAdd
+                                     ? Instruction::FAdd
+                                     : Instruction::FSub,
+                                 EndValue, ScaledStep);
+      }
+    }
+  }
+

   // An external user of the last iteration's value should see the value that
   // the remainder loop uses to initialize its own IV.
